<?php
namespace Tests\Unit\Domain\Combat;use App\Domain\Combat\CombatSide;use App\Domain\Combat\CombatStateStatus;use App\Domain\Combat\Data\CombatParticipantState;use App\Domain\Combat\Data\CombatState;use App\Domain\Combat\Data\CombatantStats;use PHPUnit\Framework\TestCase;class CombatStateTest extends TestCase{private function p($id,$side,$position,$health=10){$s=new CombatantStats($id,$id,10,$health,1,0,0,0,0,1,1,0);return new CombatParticipantState($s,$health,$side,$position);}public function test_derived_next_actor_and_queries(){$s=new CombatState([$this->p('p',CombatSide::PLAYERS,1),$this->p('e',CombatSide::ENEMIES,1)],1,['p','e'],1,CombatStateStatus::IN_PROGRESS);$this->assertSame('e',$s->nextActorIdentifier());$this->assertCount(1,$s->livingParticipantsForSide(CombatSide::PLAYERS));}public function test_duplicate_ids_and_positions_rejected(){foreach([[$this->p('x',CombatSide::PLAYERS,1),$this->p('x',CombatSide::ENEMIES,1)],[$this->p('p1',CombatSide::PLAYERS,1),$this->p('p2',CombatSide::PLAYERS,1),$this->p('e',CombatSide::ENEMIES,1)]] as $participants){try{new CombatState($participants,1,array_map(function($p){return$p->identifier();},$participants),0,CombatStateStatus::IN_PROGRESS);$this->fail();}catch(\InvalidArgumentException $e){$this->assertTrue(true);}}}}
